eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   getPostBySlug: () => (/* binding */ getPostBySlug),\n/* harmony export */   posts: () => (/* binding */ posts)\n/* harmony export */ });\nconst posts = [\n    {\n        slug: \"annual-leave-basics\",\n        title: \"연차휴가 완전 정리: 발생 기준부터 관리 팁까지\",\n        date: \"2026-03-01\",\n        category: \"연차\",\n        summary: \"연차휴가 발생 기준, 사용 촉진 제도, 관리 시 놓치기 쉬운 컴플라이언스 포인트를 정리했습니다.\",\n        readingTime: \"7분\",\n        content: `\r\n연차휴가는 근로자에게 보장된 가장 기본적인 휴식 제도입니다. 하지만 실제 현장에서는 발생 기준과 사용 촉진, 미사용 수당 정산 등에서 다양한 이슈가 발생합니다.\r\n\r\n## 1. 연차휴가 발생 기준\r\n\r\n연차휴가는 1년간 80% 이상 출근한 근로자에게 15일이 발생하는 것이 원칙입니다. 다만, 1년 미만 근로자에게는 매월 개근 시 1일씩의 연차가 발생합니다.\r\n\r\n- 1년 미만: 매월 개근 시 1일\r\n- 1년 이상, 80% 이상 출근: 연 15일\r\n- 3년 이상 근속 시: 2년에 1일씩 가산 (최대 25일)\r\n\r\n## 2. 연차 사용 촉진 제도\r\n\r\n사용자가 연차 사용 촉진 절차를 적법하게 진행한 경우, 미사용 연차에 대한 수당 지급 의무가 면제됩니다. 때문에 HR에서는 연차 사용 촉진 메일 발송, 사용 계획 확인 등의 절차를 체계적으로 관리해야 합니다.\r\n\r\n## 3. HR이 체크해야 할 포인트\r\n\r\n1. 입사일 기준 vs 회계연도 기준 관리 방식 정립\r\n2. 전사 공통 규정과 조직별 관행의 차이 파악\r\n3. 잔여 연차 현황을 정기적으로 리포팅\r\n\r\n연차는 단순 휴가 관리가 아니라 조직 구성원의 피로도와 몰입도에 직결되는 중요한 제도입니다. HR은 법적 컴플라이언스를 지키는 동시에, 구성원이 눈치 보지 않고 휴가를 사용할 수 있는 문화를 함께 설계해야 합니다.\r\n    `\n    },\n    {\n        slug: \"severance-pay-guide\",\n        title: \"퇴직금 정산 가이드: 평균임금 계산과 실무 체크리스트\",\n        date: \"2026-02-20\",\n        category: \"퇴직금\",\n        summary: \"퇴직금의 기본 개념부터 평균임금 산정, 자주 발생하는 실수까지 HR 관점에서 정리했습니다.\",\n        readingTime: \"8분\",\n        content: `\r\n퇴직금은 퇴직 근로자의 생활 안정을 위한 제도로, HR 실무에서 오류가 발생하기 쉬운 영역 중 하나입니다.\r\n\r\n## 1. 퇴직금의 기본 구조\r\n\r\n퇴직금은 '1년에 평균임금 30일분 이상'을 지급하는 것이 원칙입니다. 여기서 핵심은 **평균임금**의 산정입니다.\r\n\r\n## 2. 평균임금 산정 시 포함/제외 항목\r\n\r\n평균임금은 퇴직 전 3개월 동안 지급된 임금을 기준으로 계산합니다. 이때 다음 항목들을 구분해야 합니다.\r\n\r\n- 포함 가능성이 높은 항목: 기본급, 고정수당, 정기상여 등\r\n- 쟁점이 되는 항목: 인센티브, 성과급, 각종 수당\r\n\r\n내부 규정과 실제 지급 관행을 함께 검토하여, 어떤 항목을 평균임금에 포함할지 명확히 정의해 두는 것이 중요합니다.\r\n\r\n## 3. HR 실무 체크리스트\r\n\r\n1. 퇴직 예정자 리스트를 사전에 파악하고 시뮬레이션 진행\r\n2. 퇴직 사유(자발/비자발)에 따른 사례별 가이드 정리\r\n3. 퇴직 프로세스(면담–서류–정산–퇴직 후 안내) 표준화\r\n\r\n퇴직금 오류는 소송으로 이어질 가능성이 높기 때문에, HR은 규정 설계부터 계산 로직, 커뮤니케이션까지 전 과정을 면밀히 관리해야 합니다.\r\n    `\n    },\n    {\n        slug: \"four-major-insurances\",\n        title: \"4대보험 한 번에 이해하기: 가입부터 변경\\xb7상실 신고까지\",\n        date: \"2026-02-05\",\n        category: \"4대보험\",\n        summary: \"국민연금, 건강보험, 고용보험, 산재보험의 기본 개념과 HR이 챙겨야 할 실무 포인트를 정리했습니다.\",\n        readingTime: \"10분\",\n        content: `\r\n4대보험은 모든 기업이 반드시 관리해야 하는 기본 인사·노무 영역입니다. 하지만 각 보험별로 기관과 규정이 달라 헷갈리기 쉽습니다.\r\n\r\n## 1. 4대보험의 기본 구성\r\n\r\n- 국민연금: 노후 소득 보장\r\n- 건강보험: 질병·부상 시 의료비 지원\r\n- 고용보험: 실업급여 및 고용안정 사업\r\n- 산재보험: 업무상 재해 보상\r\n\r\n## 2. 입·퇴사 시 HR 체크 포인트\r\n\r\n1. 입사일 기준 자격 취득 신고 기한 준수\r\n2. 근로시간·급여 수준에 따른 가입 대상 여부 판단\r\n3. 퇴사일 기준 자격 상실 신고 및 보험료 정산\r\n\r\n## 3. 조직 성장 단계별 관리 전략\r\n\r\n스타트업·중소기업의 경우, 인사담당자 1명이 4대보험부터 급여, 평가까지 모두 맡는 경우가 많습니다. 이때는 다음과 같은 원칙이 도움이 됩니다.\r\n\r\n- 신고 기한 위주의 캘린더 관리\r\n- 급여 시스템과 4대보험 신고 시스템의 데이터 일관성 확보\r\n- 외부 노무사·보험사와의 협업 구조 설계\r\n\r\n4대보험은 잘하면 티가 나지 않지만, 한 번 실수하면 리스크가 크게 드러나는 영역입니다. HR은 '문제없이 돌아가고 있는 것' 자체가 성과라는 관점에서, 안정적인 운영 체계를 갖추는 데 집중해야 합니다.\r\n    `\n    }\n];\nfunction getPostBySlug(slug) {\n    return posts.find((post)=>post.slug === slug);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./lib/posts.js\n");

